'use client'
import { batch, cn, useSignal, useSignalEffect, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useId, useRef, type KeyboardEvent, type ReactNode } from 'react'
import { Kbd } from '../kbd/kbd'
import { Spinner } from '../spinner/spinner'
import styles from './command-menu.module.css'

export interface CommandPage {
  placeholder?: string
  groups: CommandGroup[]
}

export interface CommandItem {
  id: string
  label: string
  icon?: ReactNode
  shortcut?: string[]
  keywords?: string[]
  /** Exactly one of onSelect or page is required */
  onSelect?: () => void
  disabled?: boolean
  page?: CommandPage
}

export interface CommandGroup {
  heading?: string
  items: CommandItem[]
}

export interface CommandMenuProps {
  open: boolean
  onOpenChange: (open: boolean) => void
  groups: CommandGroup[]
  placeholder?: string
  emptyLabel?: string
  hotkey?: boolean
  label?: string
  loading?: boolean
  onQueryChange?: (query: string) => void
  className?: string
}

/**
 * Fuzzy subsequence matcher. Every character of `query` must appear in order
 * (case-insensitive) in `text`. Returns 0 for no match; higher is better.
 * Consecutive runs and word-start matches score bonuses.
 */
export function fuzzyScore(query: string, text: string): number {
  if (query.length === 0) return 1
  const q = query.toLowerCase()
  const t = text.toLowerCase()
  let score = 0
  let qi = 0
  let prevMatch = -2
  for (let ti = 0; ti < t.length && qi < q.length; ti++) {
    if (t[ti] !== q[qi]) continue
    score += 1
    // Consecutive-run bonus
    if (ti === prevMatch + 1) score += 4
    // Start-of-word bonus
    const before = ti === 0 ? ' ' : t[ti - 1]
    if (before === ' ' || before === '-' || before === '_' || before === '/') score += 8
    prevMatch = ti
    qi++
  }
  return qi === q.length ? score : 0
}

function itemScore(query: string, item: CommandItem): number {
  let best = fuzzyScore(query, item.label)
  for (const keyword of item.keywords ?? []) {
    const score = fuzzyScore(query, keyword)
    if (score > best) best = score
  }
  return best
}

export function CommandMenu({
  open,
  onOpenChange,
  groups,
  placeholder,
  emptyLabel,
  hotkey = true,
  label,
  loading = false,
  onQueryChange,
  className,
}: CommandMenuProps) {
  useSignals()
  const resolvedLabel = label ?? t(builtin.commandMenu.label)
  const resolvedEmptyLabel = emptyLabel ?? t(builtin.commandMenu.empty)
  const baseId = useId()
  const listboxId = `${baseId}-listbox`
  const dialogRef = useRef<HTMLDialogElement>(null)
  const inputRef = useRef<HTMLInputElement>(null)
  const optionRefs = useRef<(HTMLDivElement | null)[]>([])

  const onOpenChangeRef = useRef(onOpenChange)
  onOpenChangeRef.current = onOpenChange
  const onQueryChangeRef = useRef(onQueryChange)
  onQueryChangeRef.current = onQueryChange

  // Sync controlled props into signals — no-op when unchanged
  const isOpen = useSignal(open)
  isOpen.value = open
  const hotkeyEnabled = useSignal(hotkey)
  hotkeyEnabled.value = hotkey

  const query = useSignal('')
  const activeIndex = useSignal(0)
  const pageStack = useSignal<CommandPage[]>([])

  const activeGroups = pageStack.value.at(-1)?.groups ?? groups
  const activePlaceholder =
    placeholder ?? pageStack.value.at(-1)?.placeholder ?? t(builtin.commandMenu.placeholder)

  // Filter + rank: groups with no matching items disappear
  const filteredGroups = activeGroups
    .map((group) => ({
      heading: group.heading,
      items: group.items
        .map((item) => ({ item, score: itemScore(query.value, item) }))
        .filter(({ score }) => score > 0)
        .sort((a, b) => b.score - a.score)
        .map(({ item }) => item),
    }))
    .filter((group) => group.items.length > 0)

  const flatItems = filteredGroups.flatMap((group) => group.items)
  const enabledIndexes = flatItems.flatMap((item, index) => (item.disabled ? [] : [index]))
  const active = enabledIndexes.includes(activeIndex.value)
    ? activeIndex.value
    : (enabledIndexes[0] ?? -1)
  const optionId = (index: number) => `${baseId}-option-${index}`

  // Open / close the native dialog; opening resets query + active + stack and focuses the input
  useSignalEffect(() => {
    const dialog = dialogRef.current
    if (!dialog) return
    if (isOpen.value) {
      if (!dialog.open) {
        batch(() => {
          query.value = ''
          activeIndex.value = 0
          pageStack.value = []
        })
        if (typeof dialog.showModal === 'function') dialog.showModal()
        inputRef.current?.focus()
      }
    } else if (dialog.open) {
      pageStack.value = []
      dialog.close()
    }
  })

  // Native 'close' (Escape via cancel, programmatic close) → notify parent
  useSignalEffect(() => {
    const dialog = dialogRef.current
    if (!dialog) return
    const handler = () => onOpenChangeRef.current(false)
    dialog.addEventListener('close', handler)
    return () => dialog.removeEventListener('close', handler)
  })

  // Global Cmd/Ctrl+K hotkey
  useSignalEffect(() => {
    if (!hotkeyEnabled.value) return
    const handler = (event: globalThis.KeyboardEvent) => {
      if ((event.metaKey || event.ctrlKey) && event.key.toLowerCase() === 'k') {
        event.preventDefault()
        onOpenChangeRef.current(!isOpen.value)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  })

  const setActive = (index: number) => {
    activeIndex.value = index
    const el = optionRefs.current[index]
    if (el && typeof el.scrollIntoView === 'function') el.scrollIntoView({ block: 'nearest' })
  }

  const moveActive = (delta: number) => {
    if (enabledIndexes.length === 0) return
    const position = enabledIndexes.indexOf(active)
    const next = enabledIndexes[(position + delta + enabledIndexes.length) % enabledIndexes.length]
    if (next !== undefined) setActive(next)
  }

  const selectItem = (item: CommandItem | undefined) => {
    if (!item || item.disabled) return
    if (item.page) {
      batch(() => {
        pageStack.value = [...pageStack.value, item.page!]
        query.value = ''
        activeIndex.value = 0
      })
    } else {
      item.onSelect?.()
      onOpenChange(false)
    }
  }

  const popPage = () => {
    batch(() => {
      pageStack.value = pageStack.value.slice(0, -1)
      query.value = ''
      activeIndex.value = 0
    })
  }

  const handleInputKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
    switch (event.key) {
      case 'ArrowDown':
        event.preventDefault()
        moveActive(1)
        break
      case 'ArrowUp':
        event.preventDefault()
        moveActive(-1)
        break
      case 'Home':
        event.preventDefault()
        if (enabledIndexes[0] !== undefined) setActive(enabledIndexes[0])
        break
      case 'End': {
        event.preventDefault()
        const last = enabledIndexes[enabledIndexes.length - 1]
        if (last !== undefined) setActive(last)
        break
      }
      case 'Enter':
        event.preventDefault()
        if (active >= 0) selectItem(flatItems[active])
        break
      case 'Backspace':
        if (query.value === '' && pageStack.value.length > 0) {
          event.preventDefault()
          popPage()
        }
        break
    }
  }

  const handleDialogKeyDown = (event: KeyboardEvent<HTMLDialogElement>) => {
    if (event.key === 'Escape') {
      event.preventDefault()
      if (pageStack.value.length > 0) {
        popPage()
      } else {
        dialogRef.current?.close()
      }
    }
  }

  const handleBackdropClick = (event: React.MouseEvent<HTMLDialogElement>) => {
    if (event.target === dialogRef.current) {
      dialogRef.current?.close()
    }
  }

  let flatIndex = -1

  return (
    <dialog
      ref={dialogRef}
      aria-label={resolvedLabel}
      className={cn(styles['dialog'], className)}
      onClick={handleBackdropClick}
      onKeyDown={handleDialogKeyDown}
    >
      <div className={styles['panel']}>
        <div className={styles['search']}>
          <svg
            className={styles['searchIcon']}
            aria-hidden="true"
            viewBox="0 0 16 16"
            width="16"
            height="16"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
          >
            <circle cx="7" cy="7" r="4.5" />
            <line x1="10.5" y1="10.5" x2="14" y2="14" />
          </svg>
          <input
            ref={inputRef}
            type="text"
            role="combobox"
            aria-expanded="true"
            aria-controls={listboxId}
            aria-activedescendant={active >= 0 ? optionId(active) : undefined}
            aria-autocomplete="list"
            aria-label={resolvedLabel}
            autoComplete="off"
            spellCheck={false}
            className={styles['input']}
            placeholder={activePlaceholder}
            value={query.value}
            onChange={(event) => {
              query.value = event.target.value
              activeIndex.value = 0
              onQueryChangeRef.current?.(event.target.value)
            }}
            onKeyDown={handleInputKeyDown}
          />
        </div>
        <div className={styles['list']}>
          <div role="listbox" id={listboxId} aria-label={label}>
            {filteredGroups.map((group, groupIndex) => (
              <div
                key={group.heading ?? `group-${groupIndex}`}
                role="group"
                aria-label={group.heading}
                className={styles['group']}
              >
                {group.heading && (
                  <div className={styles['heading']} aria-hidden="true">
                    {group.heading}
                  </div>
                )}
                {group.items.map((item) => {
                  flatIndex++
                  const index = flatIndex
                  return (
                    <div
                      key={item.id}
                      ref={(el) => {
                        optionRefs.current[index] = el
                      }}
                      id={optionId(index)}
                      role="option"
                      aria-selected={index === active}
                      aria-disabled={item.disabled || undefined}
                      data-state={index === active ? 'active' : undefined}
                      data-disabled={item.disabled || undefined}
                      className={styles['option']}
                      onMouseEnter={() => {
                        if (!item.disabled) activeIndex.value = index
                      }}
                      onClick={() => selectItem(item)}
                    >
                      {item.icon && (
                        <span className={styles['icon']} aria-hidden="true">
                          {item.icon}
                        </span>
                      )}
                      <span className={styles['label']}>{item.label}</span>
                      {item.shortcut && (
                        <span className={styles['shortcut']} aria-hidden="true">
                          {item.shortcut.map((key, keyIndex) => (
                            <Kbd key={keyIndex} size="sm">
                              {key}
                            </Kbd>
                          ))}
                        </span>
                      )}
                    </div>
                  )
                })}
              </div>
            ))}
          </div>
          {flatItems.length === 0 &&
            (loading ? (
              <div role="status" className={styles['empty']}>
                <Spinner size="sm" />
                {t(builtin.commandMenu.loading)}
              </div>
            ) : (
              <div role="status" className={styles['empty']}>
                {resolvedEmptyLabel}
              </div>
            ))}
        </div>
        <div className={styles['footer']} aria-hidden="true">
          <span className={styles['hint']}>
            <Kbd size="sm">↑</Kbd>
            <Kbd size="sm">↓</Kbd> to navigate
          </span>
          <span className={styles['hint']}>
            <Kbd size="sm">↵</Kbd> to select
          </span>
          <span className={styles['hint']}>
            <Kbd size="sm">esc</Kbd> to close
          </span>
        </div>
      </div>
    </dialog>
  )
}

@layer cascivo.component {
  .dialog {
    padding: 0;
    border: none;
    border-radius: var(--cascivo-radius-overlay);
    background: transparent;
    margin-block-start: 15vh;
    margin-inline: auto;
    inline-size: min(40rem, calc(100vw - var(--cascivo-space-8)));
    max-block-size: calc(85vh - var(--cascivo-space-16));
    overflow: visible;

    /* Exit animation: transitioning `display`/`overlay` with allow-discrete
       keeps the dialog visible (and in the top layer) until the fade ends */
    opacity: 0;
    scale: 0.96;
    transition:
      opacity var(--cascivo-motion-exit),
      scale var(--cascivo-motion-exit),
      display var(--cascivo-duration-150) allow-discrete,
      overlay var(--cascivo-duration-150) allow-discrete;

    &[open] {
      opacity: 1;
      scale: 1;
      transition:
        opacity var(--cascivo-motion-enter),
        scale var(--cascivo-motion-enter),
        display var(--cascivo-duration-200) allow-discrete,
        overlay var(--cascivo-duration-200) allow-discrete;

      @starting-style {
        opacity: 0;
        scale: 0.96;
      }
    }

    /* Backdrop */
    &::backdrop {
      background-color: rgb(0 0 0 / 0.5);
      backdrop-filter: blur(2px);
      opacity: 0;
      transition:
        opacity var(--cascivo-motion-exit),
        display var(--cascivo-duration-150) allow-discrete,
        overlay var(--cascivo-duration-150) allow-discrete;
    }

    &[open]::backdrop {
      opacity: 1;
      transition:
        opacity var(--cascivo-motion-enter),
        display var(--cascivo-duration-200) allow-discrete,
        overlay var(--cascivo-duration-200) allow-discrete;

      @starting-style {
        opacity: 0;
      }
    }
  }

  .panel {
    display: flex;
    flex-direction: column;
    background-color: var(--cascivo-color-surface-overlay);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-overlay);
    overflow: hidden;
  }

  .search {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-3);
    padding-inline: var(--cascivo-space-4);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .searchIcon {
    flex-shrink: 0;
    color: var(--cascivo-color-text-muted);
  }

  .input {
    flex: 1;
    block-size: 3rem;
    padding: 0;
    border: none;
    background: transparent;
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-base);
    color: var(--cascivo-color-text);

    &:focus {
      outline: none;
    }

    &::placeholder {
      color: var(--cascivo-color-text-muted);
    }
  }

  .list {
    overflow-y: auto;
    max-block-size: 20rem;
    padding: var(--cascivo-space-2);
  }

  .group + .group {
    margin-block-start: var(--cascivo-space-2);
  }

  .heading {
    padding-inline: var(--cascivo-space-2);
    padding-block: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-xs);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text-subtle);
  }

  .option {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-3);
    padding-inline: var(--cascivo-space-2);
    padding-block: var(--cascivo-space-2);
    border-radius: var(--cascivo-radius-item);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    cursor: pointer;
    user-select: none;

    &[data-state='active'] {
      /* bg-subtle collapses to the panel surface in some themes (e.g. dark),
         making the selection invisible — use an accent tint that stays distinct. */
      background-color: var(--cascivo-color-accent-muted);
    }

    &[data-disabled] {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .icon {
    display: inline-flex;
    flex-shrink: 0;
    align-items: center;
    color: var(--cascivo-color-text-muted);
  }

  .label {
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .shortcut {
    display: inline-flex;
    gap: var(--cascivo-space-1);
    margin-inline-start: auto;
  }

  .empty {
    padding-block: var(--cascivo-space-8);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-muted);
    text-align: center;
  }

  .footer {
    display: flex;
    gap: var(--cascivo-space-4);
    padding-inline: var(--cascivo-space-4);
    padding-block: var(--cascivo-space-2);
    border-block-start: 1px solid var(--cascivo-color-border);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-subtle);
  }

  .hint {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
  }
}
